// Map common city names across languages for cross-language search
const CITY_NAME_VARIANTS: Record<string, string[]> = {
  "香港": ["Hong Kong"], "澳门": ["Macau", "Macao"], "东京": ["Tokyo"], "大阪": ["Osaka"],
  "里斯本": ["Lisbon", "Lisboa"], "波尔图": ["Porto"], "伦敦": ["London"], "巴黎": ["Paris"],
  "纽约": ["New York"], "首尔": ["Seoul"], "柏林": ["Berlin"], "马德里": ["Madrid"], "罗马": ["Rome", "Roma"],
  "hong kong": ["香港"], "macau": ["澳门"], "tokyo": ["东京"], "osaka": ["大阪"],
  "lisbon": ["里斯本"], "london": ["伦敦"], "paris": ["巴黎"], "new york": ["纽约"], "seoul": ["首尔"],
};

function getCitySearchVariants(query: string): string[] {
  return CITY_NAME_VARIANTS[query.toLowerCase()] || CITY_NAME_VARIANTS[query] || [];
}

export const useRestaurants = (searchQuery?: string, typeFilter?: string) => {
  return useQuery({
    queryKey: ["restaurants", searchQuery, typeFilter],
    queryFn: async () => {
      // Fetch all restaurants using pagination to bypass 1000-row limit
      const pageSize = 1000;
      let allData: Restaurant[] = [];
      let from = 0;
      let hasMore = true;

      while (hasMore) {
        let query = supabase
          .from("restaurants")
          .select("id,name,name_en,name_pt,address,lat,lng,phone,opening_hours,type,type_en,type_pt,rating,image_url,cover_image_url,visible,template,photo_story_zh,photo_story_en,photo_story_pt,created_at,store_level,country,city,translations,michelin_stars")
          .eq("visible", true)
          .order("rating", { ascending: false })
          .range(from, from + pageSize - 1);

        if (searchQuery) {
          const searchTerms = [searchQuery, ...getCitySearchVariants(searchQuery)];
          const orConditions = searchTerms.flatMap(term => [
            `name.ilike.%${term}%`,
            `name_en.ilike.%${term}%`,
            `name_pt.ilike.%${term}%`,
            `address.ilike.%${term}%`,
          ]);
          query = query.or([...new Set(orConditions)].join(','));
        }

        if (typeFilter) {
          const types = typeFilter.split(',');
          const allVariants = types.flatMap(type => getTypeFilterValues(type));
          const uniqueVariants = [...new Set(allVariants)];
          const orConditions = uniqueVariants.flatMap(variant => [
            `type.cs.{${variant}}`,
            `type_en.cs.{${variant}}`,
            `type_pt.cs.{${variant}}`
          ]);
          query = query.or(orConditions.join(','));
        }

        const { data, error } = await query;
        if (error) throw error;

        allData = allData.concat(data as Restaurant[]);
        hasMore = (data?.length || 0) === pageSize;
        from += pageSize;
      }

      return allData;
    },
    staleTime: 1000 * 60 * 5, // 5 minutes - avoid refetching on every navigation
    gcTime: 1000 * 60 * 15, // 15 minutes garbage collection
  });
};

export const useRestaurant = (id: string) => {
  return useQuery({
    queryKey: ["restaurant", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("*")
        .eq("id", id)
        .single();

      if (error) throw error;
      return data as Restaurant;
    },
    enabled: !!id,
  });
};

export const useFavoriteIds = () => {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["favorite-ids", user?.id],
    queryFn: async () => {
      if (!user) return [];

      const { data, error } = await supabase
        .from("favorites")
        .select("restaurant_id")
        .eq("user_id", user.id);

      if (error) throw error;
      return data.map(f => f.restaurant_id);
    },
    enabled: !!user,
  });
};

// Keep the old name for backwards compatibility but make it use the new one
export const useFavorites = useFavoriteIds;

export const useToggleFavorite = () => {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (restaurantId: string) => {
      if (!user) throw new Error("Must be logged in");

      // Check if already favorited
      const { data: existing } = await supabase
        .from("favorites")
        .select("id")
        .eq("user_id", user.id)
        .eq("restaurant_id", restaurantId)
        .maybeSingle();

      if (existing) {
        // Remove favorite
        const { error } = await supabase
          .from("favorites")
          .delete()
          .eq("id", existing.id);

        if (error) throw error;
        return { action: "removed" };
      } else {
        // Add favorite
        const { error } = await supabase
          .from("favorites")
          .insert({
            user_id: user.id,
            restaurant_id: restaurantId,
          });

        if (error) throw error;
        return { action: "added" };
      }
    },
    onMutate: async (restaurantId: string) => {
      if (!user) return;

      const queryKey = ["favorite-ids", user.id] as const;
      await queryClient.cancelQueries({ queryKey });

      const previousFavoriteIds = queryClient.getQueryData<string[]>(queryKey) || [];
      const nextFavoriteIds = previousFavoriteIds.includes(restaurantId)
        ? previousFavoriteIds.filter((id) => id !== restaurantId)
        : [...previousFavoriteIds, restaurantId];

      queryClient.setQueryData(queryKey, nextFavoriteIds);

      return { queryKey, previousFavoriteIds };
    },
    onSuccess: (result) => {
      toast.success(i18n.t(result.action === "added" ? "toast.favoriteAdded" : "toast.favoriteRemoved"));
    },
    onError: (error: any, _restaurantId, context) => {
      if (context?.queryKey && context?.previousFavoriteIds) {
        queryClient.setQueryData(context.queryKey, context.previousFavoriteIds);
      }

      if (error.message === "Must be logged in") {
        toast.error(i18n.t("toast.signInToFavorite"));
      } else {
        toast.error(i18n.t("toast.favoritesUpdateFailed"));
      }
    },
    onSettled: () => {
      if (!user) return;
      queryClient.invalidateQueries({ queryKey: ["favorite-ids", user.id] });
      queryClient.invalidateQueries({ queryKey: ["favorites-restaurants", user.id] });
      queryClient.invalidateQueries({ queryKey: ["favorites"] });
    },
  });
};

