// Reverse map: translate any localized tag back to English key (for filtering)
const reverseTypeTagMap: Record<string, string> = {};
// Build reverse map from ALL languages
for (const lang of Object.keys(typeTagTranslations)) {
  const map = typeTagTranslations[lang];
  if (map) {
    for (const [en, localized] of Object.entries(map)) {
      reverseTypeTagMap[localized] = en;
    }
  }
}
// Also map English keys to themselves
for (const key of Object.keys(typeTagTranslations.zh || {})) {
  reverseTypeTagMap[key] = key;
}

/**
 * Given a localized type label, return the English key.
 */
export function getTypeEnglishKey(localizedTag: string): string {
  return reverseTypeTagMap[localizedTag] || localizedTag;
}

