/**
 * Given a localized type label, return all DB-stored variants for filtering.
 * Expands to all member types in the category and their zh/pt translations.
 */
export function getTypeFilterValues(localizedTag: string): string[] {
  const enKey = getTypeEnglishKey(localizedTag);
  const members = TYPE_CATEGORY_MEMBERS[enKey] || [enKey];
  const values = new Set<string>();
  for (const member of members) {
    values.add(member);
    // Also add zh/pt translations from the reverse map
    const zh = typeTagTranslations.zh?.[member];
    const pt = typeTagTranslations.pt?.[member];
    if (zh) values.add(zh);
    if (pt) values.add(pt);
    // Add any known DB variants via reverse lookup
    for (const lang of Object.keys(typeTagTranslations)) {
      const localized = typeTagTranslations[lang]?.[member];
      if (localized) values.add(localized);
    }
  }
  return Array.from(values);
}

/**
 * Translate a type tag to the display language.
 * Input can be in any DB language (zh, en, pt). Output is the current UI language.
 * Falls back to the original tag if no translation found.
 */
export function getTypeDisplayLabel(tag: string, lang: string): string {
  // If already in the target language's map values, return as-is
  const targetMap = typeTagTranslations[lang];
  if (targetMap) {
    // Check if tag is already a value in this language
    if (Object.values(targetMap).includes(tag)) return tag;
    // Try direct English key match
    if (targetMap[tag]) return targetMap[tag];
    // Try reverse lookup: tag might be zh/pt, find English key first
    const enKey = reverseTypeTagMap[tag];
    if (enKey && targetMap[enKey]) return targetMap[enKey];
  }
  return tag;
}

