export function groupTypesByCategory(tags: string[], tab?: string): TypeGroup[] {
  const groups: Record<string, string[]> = { cuisine: [], store: [], landmark: [], michelin: [], other: [] };

  // Deduplicate: normalize all tags to English keys, keep only one representative per unique key
  const seenKeys = new Set<string>();
  const dedupedTags: string[] = [];
  for (const tag of tags) {
    const enKey = getTypeEnglishKey(tag);
    const normalizedKey = enKey || tag;
    if (!seenKeys.has(normalizedKey)) {
      seenKeys.add(normalizedKey);
      // Store the English key as canonical representative
      dedupedTags.push(normalizedKey);
    }
  }

  for (const tag of dedupedTags) {
    if (CUISINE_TAGS.has(tag)) groups.cuisine.push(tag);
    else if (STORE_TAGS.has(tag)) groups.store.push(tag);
    else if (LANDMARK_TAGS.has(tag)) groups.landmark.push(tag);
    else if (MICHELIN_TAGS.has(tag)) groups.michelin.push(tag);
    else groups.other.push(tag);
  }

  // Filter groups based on tab context
  const excludedGroups = new Set<string>();
  if (tab === 'landmark') {
    excludedGroups.add('cuisine');
    excludedGroups.add('store');
    excludedGroups.add('michelin');
  } else if (tab === 'michelin' || tab === 'food') {
    excludedGroups.add('landmark');
  }

  const result: TypeGroup[] = [];
  for (const key of ['cuisine', 'store', 'landmark', 'michelin', 'other'] as const) {
    if (groups[key].length > 0 && !excludedGroups.has(key)) {
      result.push({ key, label: GROUP_LABELS[key], tags: groups[key] });
    }
  }
  return result;
}

